insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('volkoren-cracker', 'Volkoren cracker', 400, 10, 65, 8, 8, 'grain', false, null, 10, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('volkoren-pita', 'Volkoren pita', 250, 9.5, 47, 1.5, 6, 'grain', false, null, 65, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('couscous', 'Couscous (gekookt)', 112, 3.8, 23, 0.2, 1.4, 'grain', false, null, null, false, 'Klaar in vijf minuten, maar qua cijfers een gewone graanbasis. Wil je meer uit je koolhydraatbasis halen, kies dan quinoa — zelfde werk, meer eiwit en vezels.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('quinoa', 'Quinoa (gekookt)', 120, 4.4, 21, 1.9, 2.8, 'grain', false, null, null, false, '4,4 gram eiwit per 100 gram gekookt — ruim het dubbele van rijst, plus extra vezels. De eiwitrijkste koolhydraatbasis die je hebt.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('roggebrood', 'Roggebrood', 190, 5.5, 38, 1.3, 8.5, 'grain', false, null, 28, false, '8,5 gram vezels per 100 gram — geen brood in de winkel zit hoger. Eén plak van 28 gram is compact en vult meer dan hij weegt.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('bulgur', 'Bulgur (gekookt)', 83, 3.1, 18.6, 0.2, 4.5, 'grain', false, null, null, false, 'Voorgekookte tarwe, klaar in tien minuten, met 4,5 gram vezels per 100 gram gekookt — ruim het tienvoudige van rijst. Qua eiwit een gewone graanbasis.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('ei', 'Ei', 127, 11.5, 0.7, 9.1, 0, 'protein', false, null, 55, false, '6,3 gram eiwit per stuk, met de hoogste biologische waarde van je hele lijst. Maar ook 5 gram vet per stuk — het aantal telt.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('tonijn', 'Tonijn op water (uitgelekt)', 91, 24, 0, 1, 0, 'protein', false, null, null, false, '24 gram eiwit per 100 gram voor 91 kcal, uit een blik dat jaren houdbaar is. Op water, niet op olie — dat scheelt zo''n 100 kcal per blik.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kipfilet', 'Kipfilet (gaar)', 165, 31, 0, 3.6, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kalkoenfilet', 'Kalkoenfilet', 135, 29, 0, 1.5, 0, 'protein', false, null, null, false, '29 gram eiwit per 100 gram voor maar 135 kcal — nog magerder dan kipfilet.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('gerookte-zalm', 'Gerookte zalm', 180, 22, 0, 10, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('zalmfilet', 'Zalmfilet', 208, 20, 0, 13, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kabeljauw', 'Kabeljauw', 82, 18, 0, 0.7, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('garnalen', 'Garnalen', 99, 24, 0, 0.3, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('rundergehakt-mager', 'Mager rundergehakt (5%)', 137, 21, 0, 5, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('biefstuk', 'Biefstuk (mager)', 180, 27, 0, 7, 0, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('edamame', 'Edamame (gedopt)', 121, 12, 9, 5, 5, 'protein', false, null, null, false, '12 gram eiwit én 5 gram vezels per 100 gram — de peulvrucht die wél als eiwitbron mag meetellen.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('linzen', 'Linzen (gekookt)', 116, 9, 20, 0.4, 8, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('tofu', 'Tofu', 76, 8, 2, 4.8, 1, 'protein', false, null, null, false, null, 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('gerookte-makreel', 'Gerookte makreel', 300, 20, 0, 24, 0, 'protein', false, null, null, false, '20 gram eiwit maar ook 24 gram vet per 100 gram — de vetste vis in je lijst, mét de bijbehorende omega-3. Kleine porties, en de rest van de maaltijd mager houden.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('varkenshaas', 'Varkenshaas (gaar)', 143, 27, 0, 3.5, 0, 'protein', false, null, null, false, '27 gram eiwit per 100 gram voor 143 kcal — het magerste stuk van het varken, vrijwel kipfilet. Kort bakken, anders wordt hij droog.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kalkoengehakt', 'Kalkoengehakt', 145, 20, 0, 7, 0, 'protein', false, null, null, false, '20 gram eiwit per 100 gram met 7 gram vet — iets vetter dan je 5%-rundergehakt, maar lichter van smaak. Variatie binnen het gehaktrepertoire.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kipfilet-beleg', 'Kipfilet-beleg (vleeswaren)', 100, 21, 1, 1.5, 0, 'protein', false, null, null, false, '21 gram eiwit per 100 gram voor maar 100 kcal — de magerste vleeswaar in de winkel. Let op het etiket: smeerbare en gerookte varianten zitten flink hoger in vet.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kidneybonen', 'Kidneybonen (blik, uitgelekt)', 95, 8, 14, 0.5, 6.5, 'protein', false, null, null, false, '8 gram eiwit én 6,5 gram vezels per 100 gram, uit een blik dat jaren houdbaar is. Geen volwaardige eiwitbron, wel de goedkoopste manier om een gehaktschotel te rekken.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('gerookte-forel', 'Gerookte forel', 136, 23, 0, 4.5, 0, 'protein', false, null, null, false, '23 gram eiwit per 100 gram voor 136 kcal — de smaak van gerookte zalm met minder dan de helft van het vet. Wel gerookt, dus zouter dan verse vis.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('rookvlees', 'Rookvlees (rund)', 117, 25, 0.5, 2, 0, 'protein', false, null, null, false, '25 gram eiwit per 100 gram voor 117 kcal — naast kipfilet-beleg de magerste vleeswaar in de winkel. Wel gezouten en gerookt, dus beleg- en saladewerk, geen dagelijkse hoofdbron.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('tempeh', 'Tempeh', 192, 20, 7, 11, 6, 'protein', false, null, null, false, '20 gram eiwit per 100 gram — ruim het dubbele van tofu, omdat tempeh uit hele gefermenteerde sojabonen bestaat. Steviger van beet, en met 6 gram vezels die tofu niet heeft.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('rode-linzen', 'Rode linzen (gekookt)', 110, 8.5, 19, 0.4, 4, 'protein', false, null, null, false, 'Zonder weken in een kwartier gaar, en ze koken vanzelf stuk tot een dikke dahl. Iets minder vezels dan gewone linzen, zelfde eiwit.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('walnoot', 'Walnoot', 654, 15, 14, 65, 7, 'nut', true, 'walnoot', null, false, 'Veruit de meeste plantaardige omega-3 (ALA) van alle noten, en het sterkste onderzoek naar LDL-verlaging. Belangrijk: dat effect komt uit vervangen, niet uit toevoegen. Walnoten in plaats van kaas of koek is winst; walnoten er bovenop is 300 kcal. Doelportie: 20–25 gram per dag.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('amandel', 'Amandel', 579, 21, 22, 50, 10, 'nut', true, 'amandel', null, false, 'Meeste eiwit van alle noten, plus vitamine E en vezels. Als je één noot kiest voor je doel: deze.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('cashew', 'Cashew', 553, 18, 30, 44, 6, 'nut', true, 'cashew', null, false, 'Minste calorieën van de noten, maar ook de minste goede vetten. Prima voor de variatie.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('pistache', 'Pistache', 560, 20, 28, 45, 10, 'nut', true, 'pistache', null, false, 'Koop ze met dop. Je moet ze pellen, dus je eet automatisch langzamer en minder — en de doppen liggen als een ingebouwde teller voor je neus.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('hazelnoot', 'Hazelnoot', 628, 15, 17, 61, 9, 'nut', true, 'hazelnoot', null, false, 'Qua profiel dicht bij de walnoot, maar zonder de omega-3. Prima voor variatie binnen het notenbudget, geen vervanger van de walnoot-basis.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('pecan', 'Pecan', 691, 9, 14, 72, 9, 'nut', true, 'pecan', null, false, 'Meeste calorieën, minste eiwit van alle noten. Lekker, maar dit is dessert — geen gezondheidskeuze.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('paranoot', 'Paranoot', 659, 14, 12, 67, 8, 'nut', true, 'paranoot', 5, false, 'Eén per dag dekt je hele seleniumbehoefte. Maximaal 3 — selenium is een van de weinige voedingsstoffen waar méér echt slechter is.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('pindakaas', 'Pindakaas', 600, 25, 12, 50, 6, 'fat', false, null, null, true, 'Voor de helft vet (9 kcal per gram) en maar 25 gram eiwit per 100 gram. Het is een vetbron met een beetje eiwit — geen eiwitbron. Gecapt op 15 gram per dag: één afgestreken lepel.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('banaan', 'Banaan', 87.5, 1.1, 22.5, 0.33, 2, 'fruit', false, null, 120, false, null, 'seed', null)
